2169	// Funções de detecção e resposta a colisões (jogador vs. cenário)
2170	// ----------------------------------------------------------------------------
2171	
2172	// Testa se um cilindro vertical (centrado em pos_xz, com raio fixo e faixa de
2173	// altura [y_min, y_max]) sobrepõe a CollisionAABB 'box'. O teste é decomposto
2174	// em (1) overlap do intervalo vertical e (2) distância do centro do círculo
2175	// (projeção do cilindro no plano XZ) ao retângulo formado pela AABB em XZ.
2176	bool CylinderIntersectsAABB(glm::vec2 pos_xz, float raio, float y_min, float y_max, const CollisionAABB& box)
2177	{
2178	    // Overlap no eixo vertical (Y)
2179	    if (y_max < box.min.y || y_min > box.max.y)
2180	        return false;
2181	
2182	    // Ponto do retângulo (projeção da AABB em XZ) mais próximo do centro do círculo
2183	    float closest_x = glm::clamp(pos_xz.x, box.min.x, box.max.x);
2184	    float closest_z = glm::clamp(pos_xz.y, box.min.z, box.max.z);
2185	
2186	    float dx = pos_xz.x - closest_x;
2187	    float dz = pos_xz.y - closest_z;
2188	
2189	    return (dx*dx + dz*dz) < (raio * raio);
2190	}
2191	
2192	bool CylinderIntersectsLine(glm::vec2 pos_xz, float raio, float y_min_jogador, float y_max_jogador, const CollisionLine& line)
2193	{
2194	    // 1. Testa o overlap no eixo vertical (Y)
2195	    if (y_max_jogador < line.y_min || y_min_jogador > line.y_max)
2196	        return false;
2197	
2198	    // 2. Matemática vetorial no plano XZ
2199	    glm::vec2 ab = line.p2 - line.p1;       // Vetor da parede
2200	    glm::vec2 ap = pos_xz - line.p1;        // Vetor do início da parede até o jogador
2201	
2202	    // Calcula a projeção escalar de AP sobre AB
2203	    float proj = glm::dot(ap, ab);
2204	    float ab_len_sq = glm::dot(ab, ab);     // Comprimento da parede ao quadrado
2205	    
2206	    // Calcula 't', que é a porcentagem da projeção ao longo da parede
2207	    float t = proj / ab_len_sq;
2208	    
2209	    // Grampeia 't' entre 0 e 1 para garantir que não estamos checando um ponto além da parede
2210	    t = glm::clamp(t, 0.0f, 1.0f);
2211	
2212	    // Encontra a coordenada exata do ponto mais próximo na parede
2213	    glm::vec2 closest_point = line.p1 + t * ab;
2214	    
2215	    // Calcula a distância do jogador até esse ponto
2216	    glm::vec2 distance_vec = pos_xz - closest_point;
2217	    
2218	    // Se a distância ao quadrado for menor que o raio ao quadrado, é colisão!
2219	    return glm::dot(distance_vec, distance_vec) < (raio * raio);
2220	}
2221	
2222	// Testa se o cilindro do jogador, na posição candidata 'pos' (mesma referência
2223	// de Pos_Player — não os pés diretamente, ver PLAYER_FEET_Y_OFFSET), colide
2224	// com alguma AABB do cenário registrada em g_CollisionAABBs.
2225	//
2226	// O intervalo vertical testado é "encolhido" por COLLISION_SKIN em cada ponta:
2227	// sem isso, ao ficar exatamente apoiado no chão (pés tocando o topo da AABB do
2228	// piso) o teste consideraria o jogador permanentemente colidindo também na
2229	// horizontal, travando todo o movimento. Esse encolhimento permite uma
2230	// penetração tolerável de poucos centímetros, imperceptível no jogo.
2231	bool PlayerCollidesAt(const glm::vec3& pos)
2232	{
2233	    glm::vec2 pos_xz(pos.x, pos.z);
2234	    float feet_y = pos.y + PLAYER_FEET_Y_OFFSET;
2235	    float y_min = feet_y + COLLISION_SKIN;
2236	    float y_max = feet_y + g_PlayerCollider.altura - COLLISION_SKIN;
2237	
2238	    // Testa colisões com caixas estáticas (cenário)
2239	    for (const CollisionAABB& box : g_CollisionAABBs)
2240	    {
2241	        if (CylinderIntersectsAABB(pos_xz, g_PlayerCollider.raio, y_min, y_max, box))
2242	            return true;
2243	    }
2244	
2245	    // Testa colisões com paredes diagonais
2246	    for (const CollisionLine& line : g_CollisionLines) {
2247	        if (CylinderIntersectsLine(pos_xz, g_PlayerCollider.raio, y_min, y_max, line))
2248	            return true;
2249	    }
2250	
2251	    // Testa colisão dinâmica com a PORTA FECHADA
2252	    if (!g_IsButtonPressed) {
2253	        if (CylinderIntersectsAABB(pos_xz, g_PlayerCollider.raio, y_min, y_max, g_ClosedDoorAABB))
2254	            return true;
2255	    }
2256	
2257	    // Testa colisão dinâmica com a CAIXA
2258	    // O jogador só esbarra na caixa se NÃO estiver segurando ela
2259	    if (!g_IsHoldingBox) 
2260	    {
2261	        // Cria a matriz do cubo exatamente onde ele está no mundo agora
2262	        glm::mat4 model_cube = Matrix_Translate(g_BoxPosition.x, g_BoxPosition.y, g_BoxPosition.z) 
2263	                            * Matrix_Rotate_Y(g_BoxAngleY) 
2264	                            * Matrix_Scale(1.0f/8.0f, 1.0f/8.0f, 1.0f/8.0f);
2265	    
2266	        // Calcula a AABB da caixa naquele exato frame
2267	        CollisionAABB boxAABB = ComputeWorldAABB(
2268	            g_VirtualScene["Cube"].bbox_min, 
2269	            g_VirtualScene["Cube"].bbox_max, 
2270	            model_cube
2271	        );
2272	        
2273	        // Testa se o cilindro do jogador bateu nessa AABB gerada
2274	        if (CylinderIntersectsAABB(pos_xz, g_PlayerCollider.raio, y_min, y_max, boxAABB))
2275	            return true;    
2276	    }
2277	
2278	    // Testa colisão dinâmica com o RÁDIO
2279	    if (!g_IsHoldingRadio) 
2280	    {
2281	        // Matriz do rádio baseada em sua escala visual (1/9)
2282	        glm::mat4 model_radio = Matrix_Translate(g_RadioPosition.x, g_RadioPosition.y, g_RadioPosition.z) 
2283	                              * Matrix_Rotate_Y(g_RadioAngleY) 
2284	                              * Matrix_Scale(1.0f/9.0f, 1.0f/9.0f, 1.0f/9.0f);
2285	    
2286	        // Calcula a AABB usando as bounding boxes locais carregadas pelo tinyobj (usando a malha "Shell" como referência)
2287	        CollisionAABB radioAABB = ComputeWorldAABB(
2288	            g_VirtualScene["Shell"].bbox_min, 
2289	            g_VirtualScene["Shell"].bbox_max, 
2290	            model_radio
2291	        );
2292	        
2293	        if (CylinderIntersectsAABB(pos_xz, g_PlayerCollider.raio, y_min, y_max, radioAABB))
2294	            return true;    
2295	    }
2296	
2297	    return false;
2298	}
