2300	// Verifica se a caixa está atravessando o cenário físico
2301	bool BoxCollidesAt(glm::vec3 pos) {
2302	    // Escala aproximada do cubo no mundo (metade do tamanho total dele)
2303	    float s = 0.3f; 
2304	    glm::vec3 min_box = pos + glm::vec3(-s, -s, -s);
2305	    glm::vec3 max_box = pos + glm::vec3(s, s, s);
2306	
2307	    // Testa colisões com o cenário retilíneo (chão, teto, paredes AABB)
2308	    for (const CollisionAABB& aabb : g_CollisionAABBs) {
2309	        if (max_box.x > aabb.min.x && min_box.x < aabb.max.x &&
2310	            max_box.y > aabb.min.y && min_box.y < aabb.max.y &&
2311	            max_box.z > aabb.min.z && min_box.z < aabb.max.z) 
2312	        {
2313	            return true;
2314	        }
2315	    }
2316	    
2317	    // Testa colisões com paredes diagonais (aproveitando o teste do cilindro)
2318	    glm::vec2 pos_xz(pos.x, pos.z);
2319	    for (const CollisionLine& line : g_CollisionLines) {
2320	        // Usamos a meia-largura (s) como raio para o teste contra a linha
2321	        if (CylinderIntersectsLine(pos_xz, s, min_box.y, max_box.y, line)) {
2322	            return true;
2323	        }
2324	    }
2325	
2326	    // Testa colisão da caixa contra a PORTA FECHADA (CÓDIGO NOVO)
2327	    if (!g_IsButtonPressed) {
2328	        if (max_box.x > g_ClosedDoorAABB.min.x && min_box.x < g_ClosedDoorAABB.max.x &&
2329	            max_box.y > g_ClosedDoorAABB.min.y && min_box.y < g_ClosedDoorAABB.max.y &&
2330	            max_box.z > g_ClosedDoorAABB.min.z && min_box.z < g_ClosedDoorAABB.max.z) 
2331	        {
2332	            return true;
2333	        }
2334	    }
2335	
2336	    // Testa colisão dinâmica contra o RÁDIO
2337	    // Usa os mesmos tamanhos que você configurou no RadioCollidesAt
2338	    float r_xz = 0.15f; 
2339	    float r_y  = 0.22f; 
2340	    glm::vec3 min_radio = g_RadioPosition + glm::vec3(-r_xz, -r_y, -r_xz);
2341	    glm::vec3 max_radio = g_RadioPosition + glm::vec3(r_xz, r_y, r_xz);
2342	
2343	    // Se a AABB da caixa sobrepor a AABB do rádio, é colisão!
2344	    if (max_box.x > min_radio.x && min_box.x < max_radio.x &&
2345	        max_box.y > min_radio.y && min_box.y < max_radio.y &&
2346	        max_box.z > min_radio.z && min_box.z < max_radio.z) 
2347	    {
2348	        return true;
2349	    }
2350	
2351	    return false;
2352	}
