2395	        max_radio.y > min_box.y && min_radio.y < max_box.y &&
2396	        max_radio.z > min_box.z && min_radio.z < max_box.z) 
2397	    {
2398	        return true;
2399	    }
2400	
2401	    return false;
2402	}
