2404	bool IsButtonTriggered() {
2405	    // Definir a área do botão (o gatilho)
2406	    glm::vec3 b_min = glm::vec3(8.5f, -1.0f, -1.5f);
2407	    glm::vec3 b_max = glm::vec3(9.5f, -0.5f, -0.5f);
2408	
2409	    // Testa Jogador
2410	    // O cilindro do jogador está sobre o botão?
2411	    if (Pos_Player.x >= b_min.x && Pos_Player.x <= b_max.x &&
2412	        Pos_Player.z >= b_min.z && Pos_Player.z <= b_max.z &&
2413	        (Pos_Player.y + PLAYER_FEET_Y_OFFSET) <= b_max.y) {
