bool IsPlayerOnGround(const CollisionWorld& w, const SceneState& s, const glm::vec3& playerPos)
{
    const float probe_dist = 0.05f;
    return PlayerCollidesAt(w, s, glm::vec3(playerPos.x, playerPos.y - probe_dist, playerPos.z));
}

