python3 - <<'PY'
import re
path = "include/matrices.h"
with open(path) as f:
    src = f.read()

# 1) Prefixa 'inline' em todas as definições de função top-level (coluna 0).
src, n = re.subn(r'(?m)^(glm::mat4|glm::vec4|float|void) ([A-Za-z_]\w*)\(',
                 r'inline \1 \2(', src)
print("Funções marcadas inline:", n)
assert n == 18, f"esperava 18, marquei {n}"

# 2) Insere as funções elementares próprias antes do #endif.
novas = r'''// ===========================================================================
//  Operações vetoriais/matriciais elementares implementadas no projeto, para
//  não depender das funções equivalentes da GLM (vedadas pelo enunciado).
//  Nomes distintos dos da GLM (crossproduct/normalized/Matrix_Inverse) para
//  evitar ambiguidade por ADL ao receberem tipos glm::vec*/glm::mat*.
// ===========================================================================

// Produto vetorial entre dois vetores 3D.
inline glm::vec3 crossproduct(glm::vec3 u, glm::vec3 v)
{
    return glm::vec3(
        u.y*v.z - u.z*v.y,
        u.z*v.x - u.x*v.z,
        u.x*v.y - u.y*v.x
    );
}

// Versor (vetor unitário) de um vetor 3D.
inline glm::vec3 normalized(glm::vec3 v)
{
    float n = sqrt(v.x*v.x + v.y*v.y + v.z*v.z);
    return v / n;
}

// Inversa de uma matriz 4x4 (cofatores / adjugada dividida pelo determinante).
// Equivalente a glm::inverse. Devolve a identidade se a matriz for singular.
inline glm::mat4 Matrix_Inverse(glm::mat4 M)
{
    // Cópia linear em ordem column-major (a mesma de OpenGL/GLM): m[col*4 + row].
    float m[16];
    for (int c = 0; c < 4; ++c)
        for (int r = 0; r < 4; ++r)
            m[c*4 + r] = M[c][r];

    float inv[16];
    inv[0]  =  m[5]*m[10]*m[15] - m[5]*m[11]*m[14] - m[9]*m[6]*m[15]  + m[9]*m[7]*m[14]  + m[13]*m[6]*m[11] - m[13]*m[7]*m[10];
    inv[4]  = -m[4]*m[10]*m[15] + m[4]*m[11]*m[14] + m[8]*m[6]*m[15]  - m[8]*m[7]*m[14]  - m[12]*m[6]*m[11] + m[12]*m[7]*m[10];
    inv[8]  =  m[4]*m[9]*m[15]  - m[4]*m[11]*m[13] - m[8]*m[5]*m[15]  + m[8]*m[7]*m[13]  + m[12]*m[5]*m[11] - m[12]*m[7]*m[9];
    inv[12] = -m[4]*m[9]*m[14]  + m[4]*m[10]*m[13] + m[8]*m[5]*m[14]  - m[8]*m[6]*m[13]  - m[12]*m[5]*m[10] + m[12]*m[6]*m[9];
    inv[1]  = -m[1]*m[10]*m[15] + m[1]*m[11]*m[14] + m[9]*m[2]*m[15]  - m[9]*m[3]*m[14]  - m[13]*m[2]*m[11] + m[13]*m[3]*m[10];
    inv[5]  =  m[0]*m[10]*m[15] - m[0]*m[11]*m[14] - m[8]*m[2]*m[15]  + m[8]*m[3]*m[14]  + m[12]*m[2]*m[11] - m[12]*m[3]*m[10];
    inv[9]  = -m[0]*m[9]*m[15]  + m[0]*m[11]*m[13] + m[8]*m[1]*m[15]  - m[8]*m[3]*m[13]  - m[12]*m[1]*m[11] + m[12]*m[3]*m[9];
    inv[13] =  m[0]*m[9]*m[14]  - m[0]*m[10]*m[13] - m[8]*m[1]*m[14]  + m[8]*m[2]*m[13]  + m[12]*m[1]*m[10] - m[12]*m[2]*m[9];
    inv[2]  =  m[1]*m[6]*m[15]  - m[1]*m[7]*m[14]  - m[5]*m[2]*m[15]  + m[5]*m[3]*m[14]  + m[13]*m[2]*m[7]  - m[13]*m[3]*m[6];
    inv[6]  = -m[0]*m[6]*m[15]  + m[0]*m[7]*m[14]  + m[4]*m[2]*m[15]  - m[4]*m[3]*m[14]  - m[12]*m[2]*m[7]  + m[12]*m[3]*m[6];
    inv[10] =  m[0]*m[5]*m[15]  - m[0]*m[7]*m[13]  - m[4]*m[1]*m[15]  + m[4]*m[3]*m[13]  + m[12]*m[1]*m[7]  - m[12]*m[3]*m[5];
    inv[14] = -m[0]*m[5]*m[14]  + m[0]*m[6]*m[13]  + m[4]*m[1]*m[14]  - m[4]*m[2]*m[13]  - m[12]*m[1]*m[6]  + m[12]*m[2]*m[5];
    inv[3]  = -m[1]*m[6]*m[11]  + m[1]*m[7]*m[10]  + m[5]*m[2]*m[11]  - m[5]*m[3]*m[10]  - m[9]*m[2]*m[7]   + m[9]*m[3]*m[6];
    inv[7]  =  m[0]*m[6]*m[11]  - m[0]*m[7]*m[10]  - m[4]*m[2]*m[11]  + m[4]*m[3]*m[10]  + m[8]*m[2]*m[7]   - m[8]*m[3]*m[6];
    inv[11] = -m[0]*m[5]*m[11]  + m[0]*m[7]*m[9]   + m[4]*m[1]*m[11]  - m[4]*m[3]*m[9]   - m[8]*m[1]*m[7]   + m[8]*m[3]*m[5];
    inv[15] =  m[0]*m[5]*m[10]  - m[0]*m[6]*m[9]   - m[4]*m[1]*m[10]  + m[4]*m[2]*m[9]   + m[8]*m[1]*m[6]   - m[8]*m[2]*m[5];

    float det = m[0]*inv[0] + m[1]*inv[4] + m[2]*inv[8] + m[3]*inv[12];
    if (det == 0.0f)
        return Matrix_Identity();

    float invDet = 1.0f / det;
    glm::mat4 R;
    for (int c = 0; c < 4; ++c)
        for (int r = 0; r < 4; ++r)
            R[c][r] = inv[c*4 + r] * invDet;
    return R;
}

