// Norma Euclidiana de um vetor 3D.
inline float norm(glm::vec3 v)
{
    return sqrt(v.x*v.x + v.y*v.y + v.z*v.z);
}

// Versor (vetor unitário) de um vetor 3D.
inline glm::vec3 normalized(glm::vec3 v)
{
    return v / norm(v);
}

// Produto escalar entre dois vetores 2D / 3D (sem a restrição de w==0 imposta
// por dotproduct(glm::vec4,...)).
inline float dotproduct(glm::vec2 u, glm::vec2 v)
{
    return u.x*v.x + u.y*v.y;
}
inline float dotproduct(glm::vec3 u, glm::vec3 v)
{
    return u.x*v.x + u.y*v.y + u.z*v.z;
}

// Distância Euclidiana entre dois pontos 3D.
inline float distancePoints(glm::vec3 a, glm::vec3 b)
{
    return norm(a - b);
}

// Mínimo / máximo componente a componente de dois vetores 3D.
inline glm::vec3 Vector_Min(glm::vec3 a, glm::vec3 b)
{
    return glm::vec3(a.x < b.x ? a.x : b.x,
                     a.y < b.y ? a.y : b.y,
                     a.z < b.z ? a.z : b.z);
}
inline glm::vec3 Vector_Max(glm::vec3 a, glm::vec3 b)
{
    return glm::vec3(a.x > b.x ? a.x : b.x,
                     a.y > b.y ? a.y : b.y,
                     a.z > b.z ? a.z : b.z);
}

// Limita um escalar ao intervalo [lo, hi].
inline float clampf(float v, float lo, float hi)
{
    return v < lo ? lo : (v > hi ? hi : v);
}

// Interpolação linear entre 'a' e 'b' (t em [0,1]).
inline float lerp(float a, float b, float t)
{
    return a*(1.0f - t) + b*t;
}

