12	// Testa se um cilindro vertical (centrado em pos_xz, com raio fixo e faixa de
13	// altura [y_min, y_max]) sobrepõe a CollisionAABB 'box'. O teste é decomposto
14	// em (1) overlap do intervalo vertical e (2) distância do centro do círculo
15	// (projeção do cilindro no plano XZ) ao retângulo formado pela AABB em XZ.
16	bool CylinderIntersectsAABB(glm::vec2 pos_xz, float raio, float y_min, float y_max, const CollisionAABB& box)
17	{
18	    // Overlap no eixo vertical (Y)
19	    if (y_max < box.min.y || y_min > box.max.y)
20	        return false;
21	
22	    // Ponto do retângulo (projeção da AABB em XZ) mais próximo do centro do círculo
23	    float closest_x = clampf(pos_xz.x, box.min.x, box.max.x);
24	    float closest_z = clampf(pos_xz.y, box.min.z, box.max.z);
25	
26	    float dx = pos_xz.x - closest_x;
27	    float dz = pos_xz.y - closest_z;
28	
29	    return (dx*dx + dz*dz) < (raio * raio);
30	}
31	
32	bool CylinderIntersectsLine(glm::vec2 pos_xz, float raio, float y_min_jogador, float y_max_jogador, const CollisionLine& line)
33	{
34	    // 1. Testa o overlap no eixo vertical (Y)
35	    if (y_max_jogador < line.y_min || y_min_jogador > line.y_max)
36	        return false;
37	
38	    // 2. Matemática vetorial no plano XZ
39	    glm::vec2 ab = line.p2 - line.p1;       // Vetor da parede
40	    glm::vec2 ap = pos_xz - line.p1;        // Vetor do início da parede até o jogador
41	
42	    // Calcula a projeção escalar de AP sobre AB
43	    float proj = dotproduct(ap, ab);
44	    float ab_len_sq = dotproduct(ab, ab);     // Comprimento da parede ao quadrado
45	
46	    // Calcula 't', que é a porcentagem da projeção ao longo da parede
47	    float t = proj / ab_len_sq;
48	
49	    // Grampeia 't' entre 0 e 1 para garantir que não estamos checando um ponto além da parede
50	    t = clampf(t, 0.0f, 1.0f);
51	
52	    // Encontra a coordenada exata do ponto mais próximo na parede
53	    glm::vec2 closest_point = line.p1 + t * ab;
54	
55	    // Calcula a distância do jogador até esse ponto
56	    glm::vec2 distance_vec = pos_xz - closest_point;
57	
58	    // Se a distância ao quadrado for menor que o raio ao quadrado, é colisão!
59	    return dotproduct(distance_vec, distance_vec) < (raio * raio);
60	}
