65	        glm::vec3(local_min.x, local_min.y, local_min.z),
66	        glm::vec3(local_max.x, local_min.y, local_min.z),
67	        glm::vec3(local_min.x, local_max.y, local_min.z),
68	        glm::vec3(local_max.x, local_max.y, local_min.z),
69	        glm::vec3(local_min.x, local_min.y, local_max.z),
70	        glm::vec3(local_max.x, local_min.y, local_max.z),
71	        glm::vec3(local_min.x, local_max.y, local_max.z),
72	        glm::vec3(local_max.x, local_max.y, local_max.z),
73	    };
74	
75	    glm::vec3 world_min( std::numeric_limits<float>::max());
76	    glm::vec3 world_max(-std::numeric_limits<float>::max());
77	    for (const glm::vec3& corner : corners)
78	    {
79	        glm::vec3 world_corner = glm::vec3(model * glm::vec4(corner, 1.0f));
80	        world_min = Vector_Min(world_min, world_corner);
81	        world_max = Vector_Max(world_max, world_corner);
82	    }
83	
84	    return CollisionAABB{ world_min, world_max };
85	}
