112	    }
113	
114	    // Testa colisões com paredes diagonais
115	    for (const CollisionLine& line : w.lines) {
116	        if (CylinderIntersectsLine(pos_xz, w.player.raio, y_min, y_max, line))
117	            return true;
118	    }
119	
120	    // Testa colisão dinâmica com a PORTA FECHADA
121	    if (!s.buttonPressed) {
122	        if (CylinderIntersectsAABB(pos_xz, w.player.raio, y_min, y_max, w.closedDoor))
