128	    if (!s.holdingBox)
129	    {
130	        // Calcula a AABB da caixa naquele exato frame (model matrix vem pronta)
131	        CollisionAABB boxAABB = ComputeWorldAABB(w.boxLocalMin, w.boxLocalMax, s.boxModel);
132	
133	        // Testa se o cilindro do jogador bateu nessa AABB gerada
134	        if (CylinderIntersectsAABB(pos_xz, w.player.raio, y_min, y_max, boxAABB))
135	            return true;
136	    }
137	
138	    // Testa colisão dinâmica com o RÁDIO
139	    if (!s.holdingRadio)
140	    {
141	        // Calcula a AABB usando as bounding boxes locais carregadas pelo tinyobj
142	        // (usando a malha "Shell" como referência), cacheadas em w.
143	        CollisionAABB radioAABB = ComputeWorldAABB(w.radioLocalMin, w.radioLocalMax, s.radioModel);
144	
145	        if (CylinderIntersectsAABB(pos_xz, w.player.raio, y_min, y_max, radioAABB))
146	            return true;
147	    }
148	
149	    return false;
150	}
