325	                               const glm::mat4& projection, int depth, int level) const
326	{
327	    // Renderização recursiva (hall of mirrors DENTRO do par): olhando por
328	    // 'portal' vê-se a sala do par dele e, nela, o próprio 'portal' de novo —
329	    // repetindo a vista 'depth' níveis. A recursão é uma CADEIA (segue sempre o
330	    // mesmo portal), então cada nível aplica de novo a MESMA transitionMatrix:
331	    // a câmera do nível k é M^k * câmera_real.
332	    //
333	    // Aninhamento via stencil auto-limpante (algoritmo canônico):
334	    //   • descendo, INCR marca a janela aninhada (stencil: level-1 -> level);
335	    //   • subindo, DECR a desfaz (level -> level-1).
336	    // Ao retornar do topo o stencil volta a 0 — sem interferência entre portais
337	    // nem entre os pares, dispensando deslocamentos de ref por par.
338	    (void)projection; // a projeção (FOV) não muda entre níveis; só a 'view'.
339	    if (depth <= 0) return;
340	    const Portal& dest = other(portal);
341	
342	    // ---- 1) Marca a janela aninhada (INCR onde o pai já está marcado) ----
343	    // O nível 1 parte do fundo (stencil 0); os profundos, da janela do nível
344	    // anterior. LEQUAL: a parede do portal (DrawScene) está à mesma profundidade
345	    // do quad — LESS falharia — e a oclusão por geometria mais próxima é
346	    // preservada. O quad usa a 'view' DESTE nível (onde o portal reaparece).
347	    stampStencil(portal, view, level - 1, GL_INCR, GL_LEQUAL);
348	
349	    // ---- 2) Limpa a profundidade dentro da janela (stencil == level) ----
350	    // Empurra o depth para o "far" (1.0) na elipse, para a vista virtual poder
351	    // desenhar em qualquer profundidade.
352	    glStencilFunc(GL_EQUAL, level, 0xFF);
353	    glStencilOp(GL_KEEP, GL_KEEP, GL_KEEP);
354	    glDepthMask(GL_TRUE);
355	    glDepthFunc(GL_ALWAYS);
356	    glDepthRange(1.0f, 1.0f);
357	    drawPortalQuad(portal);
358	    glDepthRange(0.0f, 1.0f);
359	    glDepthFunc(GL_LESS);
360	
361	    // ---- 3) Câmera virtual deste nível ----
362	    // M (com giro de 180° no eixo Y local) coloca a câmera no lado oposto do
363	    // destino, olhando através dele, e espelha o movimento da câmera real (a
364	    // parte linear de dest_R * flipY * source_R⁻¹ é a identidade).
365	    glm::mat4 M = transitionMatrix(portal, dest);
366	    glm::mat4 virtualView = virtualViewThrough(M, view);
367	
368	    // ---- 4) Renderiza a CENA deste nível, recortada na janela ----
369	    // Plano de recorte (mundo): mantém só o lado da sala do portal de destino,
370	    // descartando o que está atrás dele. É o MESMO plano em todos os níveis,
371	    // pois sempre renderizamos o mundo real a partir de uma câmera deslocada.
372	    glm::vec3 n = normalized(dest.normal);
373	    glm::vec4 clipPlane(n, -dotproduct(dest.center, n) - 0.001f);
374	
375	    glUniformMatrix4fv(g_PortalGL.viewUniform, 1, GL_FALSE, glm::value_ptr(virtualView));
376	    glUniform4fv(g_PortalGL.clipPlaneUniform, 1, glm::value_ptr(clipPlane));
377	    glEnable(GL_CLIP_DISTANCE0);
378	
379	    glColorMask(GL_TRUE, GL_TRUE, GL_TRUE, GL_TRUE);
380	    glDepthMask(GL_TRUE);
381	    glDepthFunc(GL_LESS);
382	    glStencilFunc(GL_EQUAL, level, 0xFF);   // só dentro da janela deste nível
383	    glStencilOp(GL_KEEP, GL_KEEP, GL_KEEP);
384	
385	    if (g_PortalGL.drawScene) g_PortalGL.drawScene();
386	
387	    glDisable(GL_CLIP_DISTANCE0);
388	    glm::vec4 noClip(0.0f);
389	    glUniform4fv(g_PortalGL.clipPlaneUniform, 1, glm::value_ptr(noClip));
390	
391	    // ---- 4b) Molduras (bordas azul/laranja) DESTE nível ----
392	    // O DrawScene não desenha as superfícies dos portais, então sem isto os
393	    // níveis aninhados ficariam sem borda. Ficam confinadas à janela
394	    // (stencil == level, ainda ativo) e usam a virtualView do passo 4; o anel
395	    // fica FORA da elipse, sobrevivendo ao recorte que o passo 5 fará nela.
396	    drawFramePair();
397	
398	    // ---- 5) Recursão: desce um nível pela câmera virtual ----
399	    // O portal reaparece DENTRO da cena recém-desenhada; a chamada filha esculpe
400	    // a próxima janela aninhada e sobrescreve só essa região. O nível mais raso
401	    // continua íntegro fora dela.
402	    if (depth > 1)
403	        renderOneView(portal, virtualView, projection, depth - 1, level + 1);
404	
405	    // ---- 6) Desfaz a marca deste nível (DECR: level -> level-1) ----
406	    // GL_ALWAYS: mexe SÓ no stencil, na mesma região do passo 1, sem tocar a cor
407	    // (vista já desenhada) nem a profundidade.
408	    stampStencil(portal, view, level, GL_DECR, GL_ALWAYS);
409	
410	    // Restaura o estado padrão de cor/profundidade para o resto do laço.
411	    glColorMask(GL_TRUE, GL_TRUE, GL_TRUE, GL_TRUE);
412	    glDepthMask(GL_TRUE);
413	    glDepthFunc(GL_LESS);
414	}
